using UnityEditor; using UnityEngine; public class CheckPlayer { [MenuItem("DATN/Check Player")] public static void Check() { var guids = AssetDatabase.FindAssets("t:EntityData"); foreach(var g in guids) { var p = AssetDatabase.GUIDToAssetPath(g); var d = AssetDatabase.LoadAssetAtPath<EntityData>(p); if(d != null && d.id != null && d.id.Trim().ToLower() == "player") Debug.Log($"Found player! Exact id: '{d.id}', path: {p}"); } } }
